sql:
SELECT waist, bodyfat
FROM measurements_history
WHERE bodyfat > 20;

SELECT COUNT(idno) 
FROM measurements_history 
WHERE bodyfat > (SELECT AVG(bodyfat) FROM body_composition);

external_knowledge:
- "Robust core of body fat" refers to individuals with a high body fat percentage;
- "Peak of peaks" refers to the highest maximum body fat percentage;
- "Substantial layer of adipose tissue" is a metaphorical way to describe a high body fat percentage;
- "Maintained an average body fat percentage above 10%" means the average body fat percentage over all measurements is greater than 10%;
- "Minimum body fat percentage above 5%" means the lowest body fat percentage recorded is greater than 5%;
- "Measured in the last 30 days" means the most recent measurement date is within the last 30 days.

sql:
SELECT AVG(T1.bodyfat) AS average_body_fat, AVG(T1.muscle_mass) AS average_muscle_mass
FROM body_composition T1
WHERE T1.bodyfat >= (
  SELECT AVG(bodyfat)
  FROM body_composition
);

SELECT AVG(individual_avg_bodyfat) AS average_bodyfat
FROM (
  SELECT idno, AVG(bodyfat) AS individual_avg_bodyfat
  FROM measurements_history
  GROUP BY idno
  HAVING AVG(bodyfat) > (
    SELECT AVG(bodyfat) AS overall_avg_bodyfat
    FROM measurements_history
  )
);

SELECT AVG(muscle_mass) AS avg_muscle_mass, AVG(bone_density) AS avg_bone_density
FROM body_composition
WHERE idno = 1;

SELECT idno, weight
FROM individuals
WHERE weight BETWEEN 120 AND 150;

SELECT waist
FROM measurements_history
WHERE idno = 1 AND waist > (SELECT AVG(waist) FROM measurements_history WHERE idno = 1);

SELECT AVG(bodyfat) AS overall_avg_bodyfat
FROM measurements_history
WHERE waist > 80;

external_knowledge:
- `idno` is a unique identifier for each individual;
- `bodyfat` is the percentage of body fat for each measurement;
- The query groups the data by individual and calculates the average body fat percentage for each person.

- 'Adult females' refers to females aged 18 or older;
- 'Average waist measurement' is the average waist circumference calculated for each individual;
- 'Body fat percentage' is the average body fat percentage calculated for each individual.

sql:
SELECT AVG(bodyfat) AS average_bodyfat
FROM body_composition
WHERE bodyfat IS NOT NULL;

external_knowledge:
- "waistline that stretches beyond 80 cm" refers to a waist circumference greater than 80 cm;
- "muscles that make up more than 45% of their body" refers to muscle mass greater than 45%;
- "cultural background" refers to ethnicity.

- 'Male adults in their prime' refers to males aged between 20 and 40;
- 'Healthy thresholds' for body fat and waist circumference are typically set at 10% and 80 cm, respectively;
- 'Within the last two years' refers to the measurement dates between '2022-01-01' and '2023-12-31'.

sql:
SELECT idno
FROM body_composition
WHERE muscle_mass > (SELECT AVG(muscle_mass) FROM body_composition);

SELECT AVG(bodyfat) as avg_bodyfat
FROM (
  SELECT mh.idno, mh.bodyfat
  FROM measurements_history mh
  INNER JOIN (
    SELECT idno, MIN(measurement_date) as first_date, MAX(measurement_date) as last_date
    FROM measurements_history
    GROUP BY idno
  ) m ON mh.idno = m.idno AND (mh.measurement_date = m.first_date OR mh.measurement_date = m.last_date)
) T;
